// src/instances/manager.ts
var processes = new Map;
var stopLocks = new Map;
function parseCommand(command) {
  const args = [];
  let current = "";
  let inQuote = false;
  let quoteChar = "";
  for (const ch of command) {
    if (inQuote) {
      if (ch === quoteChar) {
        inQuote = false;
      } else {
        current += ch;
      }
    } else if (ch === '"' || ch === "'") {
      inQuote = true;
      quoteChar = ch;
    } else if (ch === " " || ch === "\t") {
      if (current) {
        args.push(current);
        current = "";
      }
    } else {
      current += ch;
    }
  }
  if (current)
    args.push(current);
  return args;
}
async function pipeStream(id, stream, prefix) {
  const reader = stream.getReader();
  const decoder2 = new TextDecoder;
  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done)
        break;
      const text = decoder2.decode(value, { stream: true });
      appendLog(id, text);
      const clients = getClients(id);
      if (clients) {
        for (const ws of clients) {
          try {
            ws.send(text);
          } catch {}
        }
      }
    }
  } catch {}
}
async function startInstance(id) {
  const cfg = getInstanceConfig(id);
  if (!cfg)
    return { ok: false, message: "\u5B9E\u4F8B\u4E0D\u5B58\u5728" };
  if (processes.has(id))
    return { ok: false, message: "\u5B9E\u4F8B\u5DF2\u5728\u8FD0\u884C" };
  clearLogs(id);
  const args = parseCommand(cfg.command);
  if (args.length === 0)
    return { ok: false, message: "\u542F\u52A8\u547D\u4EE4\u4E3A\u7A7A" };
  const program = args[0];
  const programArgs = args.slice(1);
  try {
    const isWindows = process.platform === "win32";
    const proc = Bun.spawn(isWindows ? ["cmd", "/c", cfg.command] : [program, ...programArgs], {
      cwd: cfg.cwd,
      env: { ...process.env, ...cfg.env },
      stdout: "pipe",
      stderr: "pipe",
      stdin: "pipe",
      ...isWindows ? {} : { shell: false }
    });
    processes.set(id, { proc });
    setStatus(id, "running", {
      pid: proc.pid,
      startedAt: Date.now(),
      exitCode: null
    });
    logger.info(`\u5B9E\u4F8B\u5DF2\u542F\u52A8: ${cfg.name} (PID: ${proc.pid})`);
    pipeStream(id, proc.stdout, "stdout");
    pipeStream(id, proc.stderr, "stderr");
    proc.exited.then((code) => {
      processes.delete(id);
      setStatus(id, "stopped", { exitCode: code });
      logger.info(`\u5B9E\u4F8B\u5DF2\u9000\u51FA: ${cfg.name} (code: ${code})`);
      const clients = getClients(id);
      if (clients) {
        const exitMsg = JSON.stringify({ type: "exit", code });
        for (const ws of clients) {
          try {
            ws.send(exitMsg);
          } catch {}
        }
      }
      removeClients(id);
      if (cfg.autoRestart && code !== 0) {
        const currentCfg = getInstanceConfig(id);
        if (!currentCfg) {
          logger.info(`\u5B9E\u4F8B ${cfg.name} \u5DF2\u88AB\u5220\u9664\uFF0C\u505C\u6B62\u81EA\u52A8\u91CD\u542F\u3002`);
          return;
        }
        logger.info(`\u5B9E\u4F8B ${cfg.name} \u5D29\u6E83\uFF0C3 \u79D2\u540E\u81EA\u52A8\u91CD\u542F...`);
        setTimeout(() => {
          if (getInstanceConfig(id)) {
            startInstance(id);
          }
        }, 3000);
      }
    });
    return { ok: true, message: "\u542F\u52A8\u6210\u529F" };
  } catch (e) {
    setStatus(id, "error", { exitCode: -1 });
    appendLog(id, `\u542F\u52A8\u5931\u8D25: ${e.message}`);
    logger.err(`\u5B9E\u4F8B\u542F\u52A8\u5931\u8D25: ${cfg.name} - ${e.message}`);
    return { ok: false, message: `\u542F\u52A8\u5931\u8D25: ${e.message}` };
  }
}
async function stopInstance(id) {
  const entry = processes.get(id);
  if (!entry)
    return { ok: false, message: "\u5B9E\u4F8B\u672A\u5728\u8FD0\u884C" };
  const existingLock = stopLocks.get(id);
  if (existingLock) {
    await existingLock;
    return { ok: true, message: "\u505C\u6B62\u6210\u529F" };
  }
  let resolveLock;
  const lockPromise = new Promise((resolve2) => {
    resolveLock = resolve2;
  });
  stopLocks.set(id, lockPromise);
  try {
    const { proc } = entry;
    const cfg = getInstanceConfig(id);
    try {
      proc.stdin.end();
      proc.kill("SIGTERM");
    } catch {}
    await Promise.race([
      proc.exited,
      new Promise((r) => setTimeout(r, 3000))
    ]);
    if (processes.has(id)) {
      try {
        proc.kill("SIGKILL");
      } catch {}
      await Promise.race([
        proc.exited,
        new Promise((r) => setTimeout(r, 1000))
      ]);
    }
    processes.delete(id);
    setStatus(id, "stopped", { exitCode: null });
    removeClients(id);
    if (cfg)
      logger.info(`\u5B9E\u4F8B\u5DF2\u505C\u6B62: ${cfg.name}`);
    return { ok: true, message: "\u505C\u6B62\u6210\u529F" };
  } finally {
    stopLocks.delete(id);
    resolveLock();
  }
}
async function restartInstance(id) {
  const stopResult = await stopInstance(id);
  if (!stopResult.ok && stopResult.message !== "\u5B9E\u4F8B\u672A\u5728\u8FD0\u884C") {
    return stopResult;
  }
  await new Promise((r) => setTimeout(r, 500));
  return startInstance(id);
}
function writeToInstance(id, data) {
  const entry = processes.get(id);
  if (!entry)
    return false;
  try {
    entry.proc.stdin.write(new TextEncoder().encode(data));
    return true;
  } catch {
    return false;
  }
}
async function deleteInstanceManager(id) {
  if (processes.has(id)) {
    const stopResult = await stopInstance(id);
    if (!stopResult.ok)
      return stopResult;
  }
  return { ok: true, message: "\u5DF2\u505C\u6B62" };
}
function isRunning(id) {
  return processes.has(id);
}

