var instanceRoutes = new Elysia().resolve(async ({ jwt: jwt2, request }) => {
  const authHeader = request.headers.get("authorization");
  const token = authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null;
  if (!token)
    return { profile: null };
  const profile = await jwt2.verify(token);
  return { profile };
}).get("/api/instances", ({ profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const instances = getAllInstances();
  return { success: true, instances };
}).post("/api/instances", async ({ body, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const { name, command, cwd, env: env3, autoRestart, nodeId } = body || {};
  if (!name || !command || !cwd) {
    return { success: false, message: "\u7F3A\u5C11\u5FC5\u8981\u53C2\u6570: name, command, cwd" };
  }
  if (nodeId && nodeId !== "__main__") {
    const node = dbGetNode(nodeId);
    if (!node)
      return { success: false, message: "\u8282\u70B9\u4E0D\u5B58\u5728" };
    try {
      const token = await exchangeApiKeyForToken(node.address, node.apiKey);
      if (!token)
        return { success: false, message: "\u5B50\u8282\u70B9\u4E0D\u53EF\u8FBE" };
      const res = await fetch(`${node.address}/api/instances`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ name, command, cwd, env: env3, autoRestart, nodeId, nodeName: node.name }),
        signal: AbortSignal.timeout(1e4)
      });
      const data = await res.json();
      return data;
    } catch (e) {
      logger.err(`\u5B50\u8282\u70B9\u5B9E\u4F8B\u521B\u5EFA\u4EE3\u7406\u5931\u8D25: ${e.message}`);
      return { success: false, message: `\u5B50\u8282\u70B9\u8BF7\u6C42\u5931\u8D25: ${e.message}` };
    }
  }
  const cfg = createInstance({ name, command, cwd, env: env3, autoRestart, nodeId: "__main__", nodeName: "\u4E3B\u8282\u70B9" });
  return { success: true, instance: cfg };
}).get("/api/instances/:id", ({ params, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const inst = getInstance(params.id);
  if (!inst)
    return { success: false, message: "\u5B9E\u4F8B\u4E0D\u5B58\u5728" };
  return { success: true, instance: inst };
}).put("/api/instances/:id", async ({ params, body, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const { name, command, cwd, env: env3, autoRestart } = body || {};
  const updated = updateInstance(params.id, {
    name,
    command,
    cwd,
    env: env3,
    autoRestart
  });
  if (!updated)
    return { success: false, message: "\u5B9E\u4F8B\u4E0D\u5B58\u5728" };
  return { success: true, instance: updated };
}).delete("/api/instances/:id", async ({ params, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const id = params.id;
  try {
    logger.info(`\u6536\u5230\u5220\u9664\u5B9E\u4F8B\u8BF7\u6C42: ${id}`);
    await deleteInstanceManager(id).catch((e) => {
      logger.warn(`\u505C\u6B62\u5B9E\u4F8B\u8FDB\u7A0B\u65F6\u51FA\u73B0\u5F02\u5E38 (\u53EF\u80FD\u5DF2\u5904\u4E8E\u50F5\u6B7B\u72B6\u6001): ${e.message}`);
    });
    const removed = removeInstance(id);
    if (!removed) {
      logger.warn(`\u5B9E\u4F8B\u4E0D\u5B58\u5728\u4E8E\u914D\u7F6E\u4E2D: ${id}`);
      return { success: false, message: "\u5B9E\u4F8B\u4E0D\u5B58\u5728" };
    }
    logger.info(`\u5B9E\u4F8B\u5DF2\u4ECE\u7CFB\u7EDF\u4E2D\u79FB\u9664: ${id}`);
    return { success: true, message: "\u5B9E\u4F8B\u5DF2\u5220\u9664" };
  } catch (e) {
    logger.err(`\u5220\u9664\u5B9E\u4F8B\u65F6\u53D1\u751F\u4E25\u91CD\u9519\u8BEF: ${e.message}`);
    removeInstance(id);
    return { success: false, message: `\u5220\u9664\u5931\u8D25: ${e.message}` };
  }
}).post("/api/instances/:id/start", async ({ params, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const result = await startInstance(params.id);
  return result;
}).post("/api/instances/:id/stop", async ({ params, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const result = await stopInstance(params.id);
  return result;
}).post("/api/instances/:id/restart", async ({ params, profile }) => {
  if (!profile)
    return { success: false, message: "\u672A\u6388\u6743" };
  const result = await restartInstance(params.id);
  return result;
});

// src/instances/ws.ts
var instanceWsRoutes = new Elysia().ws("/api/instances/:id/terminal", {
  async beforeHandle({ jwt: jwt2, request, query }) {
    const url = new URL(request.url);
    const token = url.searchParams.get("token") || request.headers.get("authorization")?.replace("Bearer ", "");
    if (!token) {
      return new Response("Unauthorized", { status: 401 });
    }
    const profile = await jwt2.verify(token);
    if (!profile) {
      return new Response("Unauthorized", { status: 401 });
    }
  },
  open(ws) {
    const id = ws.data.params.id;
    if (!id) {
      ws.close();
      return;
    }
    let clients = getClients(id);
    if (!clients) {
      clients = new Set;
      setClients(id, clients);
    }
    clients.add(ws);
    logger.info(`WS \u5BA2\u6237\u7AEF\u5DF2\u8FDE\u63A5: \u5B9E\u4F8B ${id}`);
    const logs = getLogs(id);
    if (logs.length > 0) {
      ws.send(logs.join(`
`) + `
`);
    }
    if (!isRunning(id)) {
      ws.send(JSON.stringify({ type: "exit", code: null }));
    }
  },
  message(ws, message2) {
    const id = ws.data.params.id;
    if (!id)
      return;
    const text = typeof message2 === "string" ? message2 : String(message2);
    writeToInstance(id, text);
  },
  close(ws) {
    const id = ws.data.params.id;
    if (!id)
      return;
    const clients = getClients(id);
    if (clients) {
      clients.delete(ws);
      if (clients.size === 0) {
        removeClients(id);
      }
    }
    logger.info(`WS \u5BA2\u6237\u7AEF\u5DF2\u65AD\u5F00: \u5B9E\u4F8B ${id}`);
  }
});

// src/users/index.ts
var userRoutes = new Elysia().derive(async ({ jwt: jwt2, request }) => {
  const authHeader = request.headers.get("authorization");
  const token = authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null;
  if (!token)
    return { profile: null };
  const profile = await jwt2.verify(token);
  return { profile };
}).get("/api/users", async ({ profile }) => {
  if (!profile || profile.role !== "admin") {
    return { success: false, message: "\u65E0\u6743\u9650" };
  }
  const users = dbGetAllUsers();
  return { success: true, users };
}).post("/api/users", async ({ body, profile }) => {
  if (!profile || profile.role !== "admin") {
    return { success: false, message: "\u65E0\u6743\u9650" };
  }
  const existing = dbGetUser(body.username);
  if (existing) {
    return { success: false, message: "\u7528\u6237\u540D\u5DF2\u5B58\u5728" };
  }
  const hashedPassword = hashSync(body.password, 10);
  const role = body.role || "user";
  dbInsertUser(body.username, hashedPassword, role);
  logger.info(`\u7BA1\u7406\u5458 ${profile.username} \u521B\u5EFA\u4E86\u7528\u6237 ${body.username} (${role})`);
  return { success: true, message: "\u7528\u6237\u521B\u5EFA\u6210\u529F" };
}, {
  body: t.Object({
    username: t.String(),
    password: t.String(),
    role: t.Optional(t.String())
  })
}).patch("/api/users/me/password", async ({ body, profile }) => {
  if (!profile) {
    return { success: false, message: "\u672A\u6388\u6743" };
  }
  const user = dbGetUser(profile.username);
  if (!user) {
    return { success: false, message: "\u7528\u6237\u4E0D\u5B58\u5728" };
  }
  const valid = await compare(body.oldPassword, user.password);
  if (!valid) {
    return { success: false, message: "\u539F\u5BC6\u7801\u9519\u8BEF" };
  }
  const hashedPassword = hashSync(body.newPassword, 10);
  dbUpdateUserPassword(user.id, hashedPassword);
  logger.info(`\u7528\u6237 ${profile.username} \u4FEE\u6539\u4E86\u81EA\u5DF1\u7684\u5BC6\u7801`);
  return { success: true, message: "\u5BC6\u7801\u4FEE\u6539\u6210\u529F" };
}, {
  body: t.Object({
    oldPassword: t.String(),
    newPassword: t.String()
  })
}).patch("/api/users/:id/password", async ({ params, body, profile }) => {
  if (!profile || profile.role !== "admin") {
    return { success: false, message: "\u65E0\u6743\u9650" };
  }
  const userId = Number(params.id);
  const target = dbGetUserById(userId);
  if (!target) {
    return { success: false, message: "\u7528\u6237\u4E0D\u5B58\u5728" };
  }
  const hashedPassword = hashSync(body.password, 10);
  dbUpdateUserPassword(userId, hashedPassword);
  logger.info(`\u7BA1\u7406\u5458 ${profile.username} \u4FEE\u6539\u4E86\u7528\u6237 ${target.username} \u7684\u5BC6\u7801`);
  return { success: true, message: "\u5BC6\u7801\u4FEE\u6539\u6210\u529F" };
}, {
  body: t.Object({
    password: t.String()
  })
}).delete("/api/users/:id", async ({ params, profile }) => {
  if (!profile || profile.role !== "admin") {
    return { success: false, message: "\u65E0\u6743\u9650" };
  }
  const userId = Number(params.id);
  const target = dbGetUserById(userId);
  if (!target) {
    return { success: false, message: "\u7528\u6237\u4E0D\u5B58\u5728" };
  }
  if (target.username === profile.username) {
    return { success: false, message: "\u4E0D\u80FD\u5220\u9664\u81EA\u5DF1\u7684\u8D26\u53F7" };
  }
  dbDeleteUser(userId);
  logger.info(`\u7BA1\u7406\u5458 ${profile.username} \u5220\u9664\u4E86\u7528\u6237 ${target.username}`);
  return { success: true, message: "\u7528\u6237\u5DF2\u5220\u9664" };
});

